def build_url(base, path, scheme="https"):
    return f"{scheme}://{base}{path}"


def make_client(base, scheme="https"):
    # Pre-bind `base` (and optionally `scheme`) so callers only pass `path`.
    return functools.partial(build_url, base, scheme=scheme)

