exercises.solution_code:
import functools


@functools.lru_cache(maxsize=None)
def fib(n):
    # Pure function of `n`: caching is safe and makes the naive recursion fast.
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)


def fib_calls():
    # Expose how many of the recursive calls hit the cache vs the body.
    info = fib.cache_info()
    return info.hits, info.misses


def reset():
    fib.cache_clear()

import functools


def summarize(results):
    # Fold a sequence of outcome strings into counts. The initial accumulator
    # is supplied explicitly so an empty input still returns a full summary.
    def step(acc, outcome):
        # Copy so the initial dict is never mutated (important when callers
        # reuse the same initial value across folds).
        new = dict(acc)
        new[outcome] = new.get(outcome, 0) + 1
        return new

    initial = {"passed": 0, "failed": 0, "skipped": 0}
    return functools.reduce(step, results, initial)

tests.content:
from solution import summarize


def test_counts_each_outcome():
    results = ["passed", "failed", "passed", "skipped", "passed"]
    assert summarize(results) == {"passed": 3, "failed": 1, "skipped": 1}


def test_empty_input_returns_zeroed_summary():
    # Edge: reduce with an explicit initial value must not raise on empty input.
    assert summarize([]) == {"passed": 0, "failed": 0, "skipped": 0}


def test_single_outcome():
    assert summarize(["failed"]) == {"passed": 0, "failed": 1, "skipped": 0}


def test_consumes_an_iterator():
    # Tricky: results may be a one-shot iterator, not a list. reduce must walk
    # it once and still produce the right totals.
    results = iter(["passed", "passed", "failed"])
    assert summarize(results) == {"passed": 2, "failed": 1, "skipped": 0}


def test_does_not_mutate_a_shared_initial():
    # Calling twice must not let counts leak between independent folds.
    first = summarize(["passed"])
    second = summarize(["failed"])
    assert first == {"passed": 1, "failed": 0, "skipped": 0}
    assert second == {"passed": 0, "failed": 1, "skipped": 0}

