exercises.solution_code:
import functools

_SEVERITY = {"critical": 0, "high": 1, "medium": 2, "low": 3}


def compare_failures(a, b):
    # Order by severity (critical first); break ties by name alphabetically.
    # Returns a negative / zero / positive int, the classic 3-way comparator.
    sev_a = _SEVERITY[a["severity"]]
    sev_b = _SEVERITY[b["severity"]]
    if sev_a != sev_b:
        return sev_a - sev_b
    if a["name"] < b["name"]:
        return -1
    if a["name"] > b["name"]:
        return 1
    return 0


def sort_failures(failures):
    return sorted(failures, key=functools.cmp_to_key(compare_failures))

tests.content:
from solution import compare_failures, sort_failures


def names(failures):
    return [f["name"] for f in failures]


def test_orders_by_severity():
    data = [
        {"name": "z", "severity": "low"},
        {"name": "a", "severity": "critical"},
        {"name": "m", "severity": "medium"},
    ]
    assert names(sort_failures(data)) == ["a", "m", "z"]


def test_ties_broken_by_name():
    data = [
        {"name": "beta", "severity": "high"},
        {"name": "alpha", "severity": "high"},
    ]
    assert names(sort_failures(data)) == ["alpha", "beta"]


def test_comparator_three_way_contract():
    crit = {"name": "x", "severity": "critical"}
    low = {"name": "x", "severity": "low"}
    same = {"name": "x", "severity": "critical"}
    assert compare_failures(crit, low) < 0
    assert compare_failures(low, crit) > 0
    assert compare_failures(crit, same) == 0


def test_stable_and_combined():
    # Tricky: severity dominates, name only breaks ties — a "low" item with an
    # early name must still sort after every more severe item.
    data = [
        {"name": "aaa", "severity": "low"},
        {"name": "bbb", "severity": "critical"},
        {"name": "ccc", "severity": "high"},
    ]
    assert names(sort_failures(data)) == ["bbb", "ccc", "aaa"]


def test_empty():
    assert sort_failures([]) == []
